import Foundation

protocol RealSessionChartRepositoryProtocol: Sendable { func fetchChart(sessionID: String, range: TradingChartRange, before: Date?, limit: Int?, accessToken: String) async throws -> TradingChart }
struct RealSessionChartRepository: RealSessionChartRepositoryProtocol { let client: APIClientProtocol; func fetchChart(sessionID: String, range: TradingChartRange, before: Date? = nil, limit: Int? = nil, accessToken: String) async throws -> TradingChart { var q = [URLQueryItem(name: "range", value: range.rawValue)]; if let before { q.append(.init(name: "before", value: ISO8601DateFormatter().string(from: before))) }; if let limit { q.append(.init(name: "limit", value: String(limit))) }; do { let envelope: APIEnvelope<RealSessionChartDTO> = try await client.sendEnvelope(APIEndpoint(method: .get, path: "/api/mobile/v1/real/sessions/\(sessionID)/chart", queryItems: q, headers: HTTPHeaders.bearer(accessToken))); return try RealSessionChartMapper.map(envelope: envelope) } catch APIClientError.network { throw AuthenticationError.offline } catch APIClientError.httpStatus(401, _) { throw AuthenticationError.accessTokenExpired } catch APIClientError.decoding { throw AuthenticationError.contractIncompatible } catch APIClientError.invalidVersion { throw AuthenticationError.contractIncompatible } catch let e as AuthenticationError { throw e } catch { throw AuthenticationError.serverUnavailable } } }
struct UnconfiguredRealSessionChartRepository: RealSessionChartRepositoryProtocol { func fetchChart(sessionID: String, range: TradingChartRange, before: Date?, limit: Int?, accessToken: String) async throws -> TradingChart { throw AuthenticationError.notConfigured } }
struct MockRealSessionChartRepository: RealSessionChartRepositoryProtocol { func fetchChart(sessionID: String, range: TradingChartRange, before: Date?, limit: Int?, accessToken: String) async throws -> TradingChart { PreviewFixtures.tradingChart(range: range) } }
